import json
import logging
import os
from typing import Any, Dict, Optional

import azure.functions as func
from azure.identity import ManagedIdentityCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent
from azure.core.exceptions import ResourceNotFoundError

app = func.FunctionApp(http_auth_level=func.AuthLevel.FUNCTION)


def get_env(name: str, default: Optional[str] = None) -> str:
    value = os.getenv(name, default)
    if value is None:
        raise RuntimeError(f"Missing required environment variable: {name}")
    return value


def get_credential() -> ManagedIdentityCredential:
    client_id = os.getenv("MANAGED_IDENTITY_CLIENT_ID")
    if client_id:
        return ManagedIdentityCredential(client_id=client_id)
    return ManagedIdentityCredential()


def get_blob_service_client() -> BlobServiceClient:
    account_url = get_env("STORAGE_ACCOUNT_URL")
    return BlobServiceClient(account_url=account_url, credential=get_credential())


def get_cosmos_client() -> CosmosClient:
    endpoint = get_env("COSMOS_DB_ENDPOINT")
    return CosmosClient(url=endpoint, credential=get_credential())


def get_eventgrid_client() -> EventGridPublisherClient:
    endpoint = get_env("EVENTGRID_TOPIC_ENDPOINT")
    return EventGridPublisherClient(endpoint=endpoint, credential=get_credential())


def ensure_cosmos_container() -> Any:
    client = get_cosmos_client()
    database_name = get_env("COSMOS_DB_DATABASE")
    container_name = get_env("COSMOS_DB_CONTAINER")
    partition_key_path = os.getenv("COSMOS_DB_PARTITION_KEY", "/partitionKey")

    database = client.create_database_if_not_exists(id=database_name)
    container = database.create_container_if_not_exists(
        id=container_name,
        partition_key=PartitionKey(path=partition_key_path),
    )
    return container


def parse_blob_url(blob_url: str) -> Dict[str, str]:
    if not blob_url.startswith("https://"):
        raise ValueError("blob_url must be a valid Azure Blob Storage URL")

    path = blob_url.split(".blob.core.windows.net/", 1)[-1]
    parts = path.split("/", 1)
    if len(parts) != 2:
        raise ValueError("blob_url must include container and blob path")

    return {
        "container": parts[0],
        "blob_name": parts[1],
    }


def read_blob_content(blob_url: str) -> bytes:
    parsed = parse_blob_url(blob_url)
    service = get_blob_service_client()
    blob_client = service.get_blob_client(container=parsed["container"], blob=parsed["blob_name"])
    downloader = blob_client.download_blob()
    return downloader.readall()


def process_content(blob_url: str, content: bytes) -> Dict[str, Any]:
    text = content.decode("utf-8", errors="replace")
    lines = text.splitlines()
    words = text.split()

    return {
        "id": blob_url,
        "partitionKey": "processed-files",
        "blobUrl": blob_url,
        "sizeBytes": len(content),
        "lineCount": len(lines),
        "wordCount": len(words),
        "status": "processed",
        "preview": text[:500],
    }


def write_result_to_cosmos(document: Dict[str, Any]) -> Dict[str, Any]:
    container = ensure_cosmos_container()
    return container.upsert_item(document)


def send_eventgrid_notification(result: Dict[str, Any]) -> None:
    client = get_eventgrid_client()
    topic_event = EventGridEvent(
        subject=f"/files/processed/{result['id']}",
        event_type="Contoso.FileProcessed",
        data_version="1.0",
        data={
            "id": result["id"],
            "blobUrl": result["blobUrl"],
            "status": result["status"],
            "sizeBytes": result["sizeBytes"],
            "lineCount": result["lineCount"],
            "wordCount": result["wordCount"],
        },
    )
    client.send([topic_event])


@app.route(route="process-blob", methods=["POST"])
def process_blob(req: func.HttpRequest) -> func.HttpResponse:
    try:
        body = req.get_json()
        blob_url = body.get("blobUrl")
        if not blob_url:
            return func.HttpResponse(
                json.dumps({"error": "Request body must include blobUrl"}),
                status_code=400,
                mimetype="application/json",
            )

        content = read_blob_content(blob_url)
        result = process_content(blob_url, content)
        stored = write_result_to_cosmos(result)
        send_eventgrid_notification(result)

        return func.HttpResponse(
            json.dumps(
                {
                    "message": "Blob processed successfully",
                    "result": {
                        "id": stored.get("id"),
                        "blobUrl": stored.get("blobUrl"),
                        "status": stored.get("status"),
                        "sizeBytes": stored.get("sizeBytes"),
                        "lineCount": stored.get("lineCount"),
                        "wordCount": stored.get("wordCount"),
                    },
                }
            ),
            status_code=200,
            mimetype="application/json",
        )
    except ResourceNotFoundError as e:
        logging.exception("Blob or resource not found")
        return func.HttpResponse(
            json.dumps({"error": "Referenced resource not found", "details": str(e)}),
            status_code=404,
            mimetype="application/json",
        )
    except Exception as e:
        logging.exception("Processing failed")
        return func.HttpResponse(
            json.dumps({"error": "Processing failed", "details": str(e)}),
            status_code=500,
            mimetype="application/json",
        )